			_, _ = fmt.Fprintf(runtime.Log, "startup orphan harness reaper failed: %v\n", reapErr)
		}
		emit("loop.operator_attention", map[string]any{
			"reason":       "orphan_harness_reaper_failed",
			"project_root": runtime.ProjectRoot,
			"error":        reapErr.Error(),
